dashboard.definition:
{
    "title": "Incompatible Apps",
    "description": "",
    "inputs": {
        "input_KGS7oTln": {
            "options": {
                "defaultValue": "10.0",
                "items": [
                    {
                        "label": "10.0",
                        "value": "10.0"
                    },
                    {
                        "label": "10.1",
                        "value": "10.1"
                    },
                    {
                        "label": "9.4",
                        "value": "9.4"
                    },
                    {
                        "label": "9.3",
                        "value": "9.3"
                    },
                    {
                        "label": "9.2",
                        "value": "9.2"
                    }
                ],
                "token": "target_version"
            },
            "title": "Target Splunk Version",
            "type": "input.dropdown"
        }
    },
    "defaults": {
        "dataSources": {
            "ds.search": {
                "options": {
                    "queryParameters": {
                        "earliest": "$global_time.earliest$",
                        "latest": "$global_time.latest$"
                    }
                }
            }
        },
        "visualizations": {
            "global": {
                "showProgressBar": true
            }
        }
    },
    "visualizations": {
        "viz_sfrVNbts": {
            "dataSources": {
                "primary": "ds_Yen17uV0"
            },
            "options": {
                "dataOverlayMode": "none",
                "drilldown": "none",
                "showInternalFields": false,
                "showRowNumbers": false
            },
            "type": "splunk.table"
        }
    },
    "dataSources": {
        "ds_Yen17uV0": {
            "name": "incompatible_apps",
            "options": {
                "query": "| compatibilitycheck tgt_splunk_version=$target_version$ | eval is_archived = if(is_archived=1, \"Archived\", \"Not archived\" ) | table host appid current_version compatible_versions target_splunk_version is_archived",
                "queryParameters": {
                    "earliest": "-24h@h",
                    "latest": "now"
                }
            },
            "type": "ds.search"
        }
    },
    "layout": {
        "globalInputs": [
            "input_KGS7oTln"
        ],
        "layoutDefinitions": {
            "layout_1": {
                "options": {
                    "display": "auto",
                    "height": 960,
                    "width": 1440
                },
                "structure": [
                    {
                        "item": "viz_sfrVNbts",
                        "position": {
                            "h": 250,
                            "w": 1440,
                            "x": 0,
                            "y": 5
                        },
                        "type": "block"
                    }
                ],
                "type": "absolute"
            }
        },
        "options": {
            "submitButton": true
        },
        "tabs": {
            "items": [
                {
                    "label": "New tab",
                    "layoutId": "layout_1"
                }
            ]
        }
    },
    "applicationProperties": {
        "hideEdit": false,
        "hideExport": false
    }
}
